const itemsDedup = items;

const CHUNK_SIZE = 500;
const out = [];
for (let i = 0; i < itemsDedup.length; i += CHUNK_SIZE) {
  const chunk = itemsDedup.slice(i, i + CHUNK_SIZE).map(it => it.json);
  out.push({ json: { rows: chunk } });
}
return out.length ? out : [{ json: { rows: [] } }];

